mapper.select:
SELECT/*상품정보로 유효한 정책정보를 들고온다.*/ DISTINCT C.SALE_PLCY_CD, C.SALE_PLCY_NM FROM MSP_SALE_PRDT_MST@DL_MSP A -- 정책 , CMN_INTM_MDL@DL_MSP B , MSP_SALE_PLCY_MST@DL_MSP C , MSP_RATE_MST@DL_MSP RA , MSP_SALE_RATE_MST@DL_MSP SA , MSP_SALE_ORGN_MST@DL_MSP ORG , MSP_SALE_AGRM_MST@DL_MSP AG WHERE C.PLCY_SCTN_CD = 02 AND A.PRDT_ID = B.PRDT_ID AND SA.SALE_PLCY_CD = AG.SALE_PLCY_CD AND A.SALE_PLCY_CD = C.SALE_PLCY_CD AND A.SALE_PLCY_CD = SA.SALE_PLCY_CD AND RA.RATE_CD = SA.RATE_CD AND C.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN C.SALE_STRT_DTTM AND C.SALE_END_DTTM and A.PRDT_ID = #{prdtId} AND RA.PAY_CL_CD = #{payClCd} AND C.PRDT_SCTN_CD = #{prdtSctnCd} AND ORG.ORGN_ID = #{orgnId}
AND AG.AGRM_TRM= #{agrmTrm} -- 약정기간 무약정0은 기본적으로 조회한다.
ORDER BY SALE_PLCY_CD

SELECT DISTINCT AG.AGRM_TRM ,SA.SALE_PLCY_CD --정책코드 ,RA.RATE_CD --상품코드 ,RA.RATE_NM --상품명 ,RA.PAY_CL_CD -- 선불 후불구분 PO 후불 PP선불 ,RA.DATA_TYPE -- 데이터 타입 FROM MSP_RATE_MST@DL_MSP RA, MSP_SALE_RATE_MST@DL_MSP SA, CMN_GRP_CD_MST@DL_MSP GR, MSP_SALE_AGRM_MST@DL_MSP AG WHERE APPL_END_DT = '99991231' AND RA.PAY_CL_CD = GR.CD_VAL AND SA.SALE_PLCY_CD IN
#{item}
AND RA.PAY_CL_CD = #{payClCd} AND RA.RATE_CD = SA.RATE_CD AND SA.SALE_PLCY_CD = AG.SALE_PLCY_CD

/*정책정보로 약정할인 조회.*/ SELECT --RA.SALE_PLCY_CD, RA.AGRM_TRM --RA.REGST_ID, --RA.REGST_DTTM, --RA.RVISN_ID, --RA.RVISN_DTTM FROM MSP_SALE_AGRM_MST@DL_MSP RA WHERE RA.SALE_PLCY_CD IN
#{item}
GROUP BY AGRM_TRM ORDER BY AGRM_TRM ASC

update.foreach:
 INTO MCP_USIM_PROD_SORT
(
 USIM_SEQ
 ,SALE_PLCY_CD
 ,PAY_SORT
 ,RATE_CD
 ,RATE_NM
 ,PRDT_NM
 ,PRDT_ID
 ,CRET_ID
 ,AMD_ID
 ,CRET_DT
 ,AMD_DT
 ) VALUES

     (
     #{item.usimSeq}
     , #{item.salePlcyCd}
     , #{item.paySort}
     , #{item.rateCd}
     , (SELECT NVL(RATE_NM,'-') AS RATE_NM FROM MSP_RATE_MST@DL_MSP WHERE RATE_CD = #{item.rateCd})
     , #{item.prdtNm}
     , #{item.prdtId}
     , #{item.cretId}
     , #{item.amdId}
     , SYSDATE
     , SYSDATE
     )
